var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"로터스, 대균열 지대","JPN":"ロータス、大亀裂地帯","ENG":"Lotus, Grand Dimension Crevice","TWN":"洛德斯，大峽谷地帶","DEU":"Lotus, Grand Dimension Crevice","FRA":"Lotus, Grand Dimension Crevice"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"CSE Lv. 5","JPN":"CSE Lv.5","ENG":"CSE Lv. 5","TWN":"CSE Lv.5","DEU":"CSE Lv. 5","FRA":"CSE Lv. 5"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"불경하게도, 왕의 출어를 방해하는 미물들이 남아있었구나.","JPN":"不敬にも、王の御行幸を妨げる微物どもが残っていたとは。","ENG":"How impious. Vermin remain that dare to hinder the queen's outing.","TWN":"真是大不敬，竟然還有廢物阻擋王的出巡。"},"stage":{"bg":"MAINSTREAM_124010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 충성스러운 병사들아. 왕의 첫번째 사도, 솔리키타티오가 명하겠다.","JPN":"王に忠誠を誓った兵たちよ。王の第一使徒、ソリキタティオが命ずる。","ENG":"Loyal soldiers of the queen. I, Sollicitatio, the queen's first Apostle, command you.","TWN":"王忠誠的士兵們，王的第一使徒，索爾奇塔提奧在此下令。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"우리의 앞을 막는 미물들에게 너희의 충심을 보여주거라.","JPN":"我らの行く手を阻む下等な微物どもに、お前らの忠心を示してみせよ。","ENG":"Show your devotion to the vermin that block our path.","TWN":"向擋在我們面前的廢物展現你們的忠心吧。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"저, 저게 대체…….","JPN":"あ、あれはいったい……","ENG":"W-what is that...?","TWN":"那、那到底是……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"일단 쏴!","JPN":"とりあえず撃て！","ENG":"Just fire!","TWN":"先開火再說！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"대균열 속에서 뿌리랑 함께 빠져나온 침식체다!","JPN":"大亀裂の中から根と共に現れた侵食体だ！","ENG":"It's a C.O. that rose from the Grand Dimension Crevice with the roots!","TWN":"是連同那些根一起從大峽谷裡爬出來的侵蝕體！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RPG_FOX_NULL_NULL","text":{"KOREA":"뭔지는 몰라도 여지껏 마주한 녀석들과는 다를 거야!","JPN":"よくわからないが、おそらく今までのやつらみたいにはいかないはずだ！","ENG":"Whatever it is, it won't be like the ones we've faced so far!","TWN":"不管那是什麼，肯定和之前遇到的不同！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RPG_FOX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"겁먹은 것을 숨기기 위해 도리어 공격성을 내보이다니.","JPN":"怯えていることを隠すために攻撃性を顕わにするとは。","ENG":"You brandish aggression to hide your fear.","TWN":"為了掩飾自己的恐懼反而展現攻擊性。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"지금 너희들의 모습은…….","JPN":"今の貴様らの姿は……","ENG":"Your current state is...","TWN":"你們現在的模樣……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"사뭇 가축과도 다름이 없구나.","JPN":"まるで家畜そのものだな。","ENG":"No different from livestock.","TWN":"簡直和牲畜沒兩樣。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"내 너희를 가엽게 여겨 기꺼이 왕의 병사로 재조립되는 영광을 하사하겠다.","JPN":"貴様らを憐れみ、王の兵として組み直される栄誉を授けよう。","ENG":"I shall pity you and grant the honor of being reassembled as soldiers of the queen.","TWN":"我可憐你們，賞賜你們重鑄為王的士兵的榮耀。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"흐, 흐아아아악!","JPN":"ふ、ふああああっ！","ENG":"N-no!","TWN":"呃、呃啊啊啊啊啊！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"도, 도망…… 도망가야……!","JPN":"に、逃げ……逃げないと……！","ENG":"W-we... We have to run–!","TWN":"快、快逃……快逃啊……！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"이봐! 그쪽으로 가면 안 돼!","JPN":"おい！　そっちに行っちゃダメだ！","ENG":"Hey! Don't go that way!","TWN":"喂！不能往那邊跑！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MERCENARY_NPC_ESPR2_B","text":{"KOREA":"흐윽……! 아, 아아아아아아악!","JPN":"ふっ……！　あ、ああああああっ！","ENG":"Ngh...! A-AAAARGH!","TWN":"呃……！啊、啊啊啊啊啊啊！"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MERCENARY_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"애타게 차례를 기다릴 필요는 없다.","JPN":"順番を待つまでもない。","ENG":"No need to wait anxiously for your turn.","TWN":"不必急著想趕快輪到自己。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너희 미물들을 하나하나 정성 들여 재조립할 생각은 없으니.","JPN":"一つ一つ丁寧に組み直してやるほどの価値が、貴様ら微物にあるとでも？","ENG":"I have no intent to reassemble you vermin one by one with care.","TWN":"我可不打算一一重組你們這些廢物。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하나로 반죽해 빚어주마.","JPN":"一塊にして仕上げてやろう。","ENG":"I shall knead you into one mass and mold you.","TWN":"我會把你們揉成一團。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"좋아! 그럼 이… 유해를 사용하면 차원 계면이 녹아내리는 걸 막을 수 있다는 거지?","JPN":"よし！　じゃあこの……遺骸を利用すると、次元界面が溶けるのを防げるんだよね？","ENG":"Okay! So if we use these... remains, we can stop the dimension surface from melting, right?","TWN":"很好！那麼……只要使用這個遺骸，就能阻止次元界面融解對吧？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 이 아티팩트의 파장, 원리, 구조를 얼른 파악해서 설계에 반영해야 하고…….","JPN":"ということは、このアーティファクトの波長、原理、構造を早く把握して設計に反映しないと……","ENG":"Then we must grasp the Artifact's wavelength, principle, and structure fast and feed it into the design...","TWN":"那就得趕快分析這個遺物的波長、原理與結構並應用在設計……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"거기! 이볼브 원이랑 기계수집가! 지금 만들고 있는 시스템에 몇 가지를 더 추가해야겠어!","JPN":"そこ！　イボルブ・ワンと機械収集家！　今作ってるシステムに幾つか追加するよ！","ENG":"You there! Evolved One and Machine Collector! We need a few more additions to the system in progress!","TWN":"喂！Evolved One 和機械收藏家！我要在正在建置的系統再加幾個項目！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"인플로전 리액터에 아티팩트의 파장을 가두는 차단막을 설치하고 그 파장이 이터니움의 활성화된 에너지를 안정화시켜서…….","JPN":"インプロージョン・リアクターにアーティファクトの波長を閉じ込めるバリアを張って、その波長が活性化したエタニウムのエネルギーを安定化させ……","ENG":"Install a barrier that traps the Artifact's wavelength in the implosion reactor and use that wavelength to stabilize the activated energy of Eternium...","TWN":"在內爆反應爐加裝能封鎖遺物波長的屏障，讓波長穩定永恆之金活性化後的能量……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이졸데 씨, 저렇게 들뜬 모습은 처음이에요.","JPN":"イゾルデさんがあんなにはしゃいでいる姿、初めて見ます。","ENG":"Isolde, I've never seen you this excited.","TWN":"我第一次看到伊索德這麼興奮的樣子。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"본래 은둔형 외톨이 중에는 자신과 같은 과라고 생각하면 한없이 마음이 열리는 부류가 있다고 합니다.","JPN":"引きこもりの中には、相手が自分と同類だと判断すると一気に心を開くタイプの人がいるらしいです。","ENG":"Among true shut-ins, some open their hearts completely to those they see as their own kind.","TWN":"據說有些隱居型的人只要覺得對方和自己是同類人，就會完全敞開心扉。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님은 바로 그 부류에 해당하는 분이십니다.","JPN":"シニア様はまさにそういうタイプです。","ENG":"Senior is exactly that type.","TWN":"Senior就是那種類型的人。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"최고 관리자님 앞에서도 까칠하게 굴었지만 결국 자신의 능력을 알아주는 분이셨기에 마음을 열지 않았습니까?","JPN":"最高管理者様の前でも最初は刺々しい態度でしたが、自分の能力を認めてくれる人と知り、心を開いたのです。","ENG":"She was prickly even before the Supreme Administrator, yet opened up because he recognized her ability.","TWN":"即使在最高管理者前全副武裝，最後不也因為對方理解她的才能而敞開心扉了嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"아마 자신의 능력을 알아주는 사람들이 잔뜩 있는 지금이, 시니어님에겐 천국이나 다름없을 겁니다.","JPN":"そういった人に囲まれている今は、シニア様にとって天国に等しいでしょう。","ENG":"With many people here who appreciate her talents, this must feel like heaven to her.","TWN":"現在滿滿都是知道她能力的人，對Senior來說簡直是天堂吧。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그 사람들이 극악의 범죄자들이란 건…… 시니어님에겐 고려할 바가 아니니까요.","JPN":"相手が極悪非道な犯罪者だという点は……シニア様にとって考慮対象のうちに入りませんから。","ENG":"The fact they are heinous criminals... is not a factor to her.","TWN":"那些人是壞透的罪犯這點……對Senior來說不重要。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하, 하하…… 그렇군요.","JPN":"あ、あはは……そうなんですね。","ENG":"Ha, haha... I see.","TWN":"哈、哈哈……原來如此。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};